import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, mainStageHeaderAction, mainStageHeaderStrings, breadCrumbActions, MyTable } from "../../includes";
import { routeNamesInventory } from '../routeNames';
import {  } from './actions';
import { priceListStrings, priceListActions } from './config';
import { TableCell } from '@material-ui/core';

const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _PriceList extends Component {
    constructor(props){
        super(props);
        this.state = {
            lastId : null,
            rows : 200,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PRODUCT PRICE LIST",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesInventory.dashboard},
            {name : "Product Price list", path : routeNamesInventory.itemPriceList},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : [
                {value : "New Price List", onClick :()=>this.props.history.push(routeNamesInventory.priceListNew)}
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const { dispatch } = this.props;
        const {lastId, rows} = this.state;
        priceListActions.getPriceLists(lastId, rows)(dispatch);
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes} = this.props;
        switch(cellMap){
            case  "items" : return <TableCell className={classes.cell}>
                {row.itemPrices && row.itemPrices.length}
            </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    rowAction = row => () => {
        this.props.history.push(routeNamesInventory.priceListItem_+row._id);
    }
    render() {
        const {
            classes,
            [priceListStrings.pricelists] : pricelists
        } = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["Name", "Description", "No. of Items", "Date"]}
                    dataMap={["name", "description", "items", "date"]}
                    data={pricelists}
                    CellMap={this.cellMapFormat.bind(this)}
                    rowAction={this.rowAction.bind(this)}
                    />
            </div>
        );
    }
}


_PriceList.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({priceListReducer}) => ({
    [priceListStrings.pricelists] : priceListReducer[priceListStrings.pricelists],
})


export const PriceList = connect(mapStateToProps)(withStyles(style)(_PriceList));
export {PriceList as default}